Below is the session-cookie crypto code from Apache HTTPD 2.4.25, which fixed CVE-2016-0736. The module still encrypts session data with AES-256-CBC, but it now authenticates salt ‖ IV ‖ ciphertext with a MAC that is verified BEFORE decryption:

**File: mod_session_crypto.c (Apache HTTPD 2.4.25)**
```c
/* encrypt_string(): prepend a leading MAC over salt + IV + ciphertext */
compute_auth(combined + AP_SIPHASH_DSIZE, combinedlen - AP_SIPHASH_DSIZE,
             passphrase, passlen, combined);

static apr_status_t decrypt_string(request_rec * r, const apr_crypto_t *f,
        session_crypto_dir_conf *dconf, const char *in, char **out)
{
    unsigned char auth[AP_SIPHASH_DSIZE];
    ...
    decodedlen = apr_base64_decode(decoded, in);
    /* sanity check - decoded too short? */
    if (decodedlen < (AP_SIPHASH_DSIZE + sizeof(apr_uuid_t))) {
        return APR_ECRYPT;
    }

    for (; i < dconf->passphrases->nelts; i++) {
        const char *passphrase = APR_ARRAY_IDX(dconf->passphrases, i, char *);
        apr_size_t passlen = strlen(passphrase);
        apr_size_t len = decodedlen - AP_SIPHASH_DSIZE;
        unsigned char *slider = (unsigned char *)decoded + AP_SIPHASH_DSIZE;

        /* Verify authentication of the whole salt+IV+ciphertext by computing
         * the MAC and comparing it (timing safe) with the one in the payload. */
        compute_auth(slider, len, passphrase, passlen, auth);
        if (!ap_crypto_equals(auth, decoded, AP_SIPHASH_DSIZE)) {
            ap_log_rerror(APLOG_MARK, APLOG_DEBUG, res, r, APLOGNO(), "auth does not match, skipping");
            continue;                         /* reject tampered data BEFORE decrypting */
        }

        /* ... only now derive the key, AES-256-CBC decrypt, and unpad ... */
    }
    return res;
}
```
The MAC (a keyed authentication tag over salt + IV + ciphertext) is checked first; any tampered cookie fails the constant-time comparison and is rejected before decryption, so the padding-validity result is never exposed to the attacker.

